/* a+ core 2 :: content/questions2.js — Domain 2 Security (220-1202). */
window.APLUS2 = window.APLUS2 || {};
APLUS2.questions = APLUS2.questions || [];
APLUS2.questions.push(
{ id:"D2-001", domain:2, obj:"2.1", diff:"easy", q:"A small office wants to prevent unauthorized people from following an employee through a secured door (tailgating). Which physical control directs one person through at a time, only opening the second door after the first has closed?", options:["Bollard","Access control vestibule","Badge reader","Magnetometer"], answer:1, explain:"<strong>Access control vestibule</strong> is correct because it is a small space with two interlocking doors where the inner door does not open until the outer one closes, allowing only one person through and stopping tailgating.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bollard</b>: a sturdy post that blocks vehicles, not people walking through a door.</span><span class='qd'><b>Badge reader</b>: authenticates a single credential but does nothing to stop a second person slipping in behind.</span><span class='qd'><b>Magnetometer</b>: detects metal objects on a person; it does not control door flow.</span>" },
{ id:"D2-002", domain:2, obj:"2.1", diff:"easy", q:"Which device reads a contactless card or fob to grant or deny entry to a secured area?", options:["Badge reader","Bollard","Smart card writer","KVM switch"], answer:0, explain:"<strong>Badge reader</strong> is correct because it scans an RFID/proximity badge and signals the access system to unlock the door for an authorized credential.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bollard</b>: a physical post that blocks vehicle traffic.</span><span class='qd'><b>Smart card writer</b>: programs cards but does not control door access.</span><span class='qd'><b>KVM switch</b>: shares a keyboard, video, and mouse among computers; unrelated to access control.</span>" },
{ id:"D2-003", domain:2, obj:"2.1", diff:"medium", q:"A company requires users to present a password plus a code from a hardware key fob. What category of authentication does the key fob represent?", options:["Something you know","Something you are","Something you have","Somewhere you are"], answer:2, explain:"<strong>Something you have</strong> is correct because a physical hard token (key fob) is an object in the user's possession that generates one-time codes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Something you know</b>: that describes the password, not the fob.</span><span class='qd'><b>Something you are</b>: refers to biometrics such as a fingerprint.</span><span class='qd'><b>Somewhere you are</b>: refers to location-based factors like GPS or IP geolocation.</span>" },
{ id:"D2-004", domain:2, obj:"2.1", diff:"medium", q:"An administrator wants new accounts to receive only the access needed to do their job and nothing more. Which principle is being applied?", options:["Implicit deny","Principle of least privilege","Separation of duties","Mandatory access control"], answer:1, explain:"<strong>Principle of least privilege</strong> is correct because it grants each user the minimum rights required for their role, reducing the attack surface.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Implicit deny</b>: a firewall/ACL default that blocks anything not explicitly allowed, not an account-rights principle.</span><span class='qd'><b>Separation of duties</b>: splits a sensitive task among multiple people to prevent fraud.</span><span class='qd'><b>Mandatory access control</b>: assigns access based on classification labels set by policy, not on minimizing rights per role.</span>" },
{ id:"D2-005", domain:2, obj:"2.1", diff:"medium", q:"In Active Directory, which object is used to group users and computers so a single policy or setting can be applied to all of them at once?", options:["Organizational unit","Forest trust","Login script","Home folder"], answer:0, explain:"<strong>Organizational unit</strong> is correct because an OU is a container in AD used to organize objects and target Group Policy at a specific set of users or computers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Forest trust</b>: establishes authentication between separate AD forests, not a grouping for policy.</span><span class='qd'><b>Login script</b>: runs commands at sign-in but is not a container.</span><span class='qd'><b>Home folder</b>: a per-user network storage location, not a grouping object.</span>" },
{ id:"D2-006", domain:2, obj:"2.1", diff:"easy", q:"Which Active Directory feature automatically runs commands such as mapping drives whenever a user signs in?", options:["Group Policy Object","Login script","Folder redirection","Organizational unit"], answer:1, explain:"<strong>Login script</strong> is correct because it executes a defined set of commands (drive mappings, printer connections) each time the user logs on.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Group Policy Object</b>: applies configuration settings broadly but is not itself the per-user logon command file.</span><span class='qd'><b>Folder redirection</b>: points user folders to a network location.</span><span class='qd'><b>Organizational unit</b>: a container for organizing objects, not a script.</span>" },
{ id:"D2-007", domain:2, obj:"2.1", diff:"hard", q:"A technician must enforce a corporate password complexity rule on every domain-joined workstation centrally. Which Active Directory tool accomplishes this?", options:["Local Users and Groups","Group Policy","Login script","Device Manager"], answer:1, explain:"<strong>Group Policy</strong> is correct because Group Policy Objects push security settings such as password complexity to all domain members from a central point.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Local Users and Groups</b>: only affects accounts on one machine, not the domain.</span><span class='qd'><b>Login script</b>: runs commands at logon but is not the standard mechanism for password policy.</span><span class='qd'><b>Device Manager</b>: manages hardware drivers, unrelated to password rules.</span>" },
{ id:"D2-008", domain:2, obj:"2.1", diff:"medium", q:"Which term describes a software-generated, time-based one-time code from an authenticator app on a phone?", options:["Hard token","Soft token","Smart card","SSO ticket"], answer:1, explain:"<strong>Soft token</strong> is correct because it is a software application that produces one-time passcodes, unlike a dedicated physical device.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hard token</b>: a separate physical device such as a key fob.</span><span class='qd'><b>Smart card</b>: a physical card containing a chip used for authentication.</span><span class='qd'><b>SSO ticket</b>: a credential issued by single sign-on, not a generated OTP.</span>" },
{ id:"D2-009", domain:2, obj:"2.1", diff:"easy", q:"A list attached to a file or network resource that specifies which users or groups may access it and what they may do is called a what?", options:["Access control list","Group Policy Object","Login banner","Security token"], answer:0, explain:"<strong>Access control list</strong> is correct because an ACL enumerates the permissions (read, write, etc.) granted to specific principals for a resource.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Group Policy Object</b>: a set of centrally managed configuration settings, not a per-resource permission list.</span><span class='qd'><b>Login banner</b>: a notice displayed before sign-in.</span><span class='qd'><b>Security token</b>: a credential or device used for authentication.</span>" },
{ id:"D2-010", domain:2, obj:"2.1", diff:"hard", q:"An organization deploys a mobile device management solution. What is the primary security benefit of MDM enrollment for company phones?", options:["It increases cellular signal strength","It enforces configuration policies and enables remote wipe","It replaces the need for screen locks","It blocks all incoming phone calls"], answer:1, explain:"<strong>It enforces configuration policies and enables remote wipe</strong> is correct because MDM centrally applies security settings (encryption, passcodes, app restrictions) and can wipe a lost device.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It increases cellular signal strength</b>: MDM has nothing to do with radio reception.</span><span class='qd'><b>It replaces the need for screen locks</b>: MDM actually enforces screen locks rather than removing them.</span><span class='qd'><b>It blocks all incoming phone calls</b>: that is not the purpose of MDM.</span>" },
{ id:"D2-011", domain:2, obj:"2.1", diff:"easy", q:"Which short, sturdy vertical post is installed to stop vehicles from driving into a building entrance?", options:["Bollard","Turnstile","Mantrap","Cable lock"], answer:0, explain:"<strong>Bollard</strong> is correct because a bollard is a strong post designed to block or redirect vehicle traffic and protect pedestrians and structures.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Turnstile</b>: controls pedestrian flow, not vehicles.</span><span class='qd'><b>Mantrap</b>: an older term for an access control vestibule controlling people.</span><span class='qd'><b>Cable lock</b>: secures a laptop to a desk.</span>" },
{ id:"D2-012", domain:2, obj:"2.1", diff:"medium", q:"Combining a fingerprint scan with a PIN to unlock a workstation is an example of what?", options:["Single sign-on","Multifactor authentication","Federation","Time-based access"], answer:1, explain:"<strong>Multifactor authentication</strong> is correct because it uses two different categories of factors: something you are (fingerprint) and something you know (PIN).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Single sign-on</b>: lets one login grant access to many systems; it is not two factors.</span><span class='qd'><b>Federation</b>: trusts identities across organizations.</span><span class='qd'><b>Time-based access</b>: restricts when a user can log in, not how many factors are used.</span>" },
{ id:"D2-013", domain:2, obj:"2.1", diff:"hard", q:"A domain administrator wants every department's users in one container so that a printer-deployment policy targets only Sales. Which combination is the correct approach?", options:["Place Sales users in their own OU and link a GPO to that OU","Add all users to the Domain Admins group","Apply a login banner to the domain","Use folder redirection on the file server"], answer:0, explain:"<strong>Place Sales users in their own OU and link a GPO to that OU</strong> is correct because organizing users into an OU and linking a Group Policy Object scopes the printer deployment to just those members.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add all users to the Domain Admins group</b>: grants excessive privilege and does not target a policy.</span><span class='qd'><b>Apply a login banner to the domain</b>: only shows a message; it does not deploy printers.</span><span class='qd'><b>Use folder redirection on the file server</b>: redirects user folders, unrelated to printer policy.</span>" },
{ id:"D2-014", domain:2, obj:"2.1", diff:"medium", q:"What is the security purpose of installing a video surveillance (CCTV) system at facility entrances?", options:["To encrypt network traffic","To provide detection and deterrence of unauthorized access","To replace badge readers","To authenticate users to the domain"], answer:1, explain:"<strong>To provide detection and deterrence of unauthorized access</strong> is correct because cameras record activity and their visible presence discourages intrusion.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To encrypt network traffic</b>: video cameras do not encrypt data in transit for the network.</span><span class='qd'><b>To replace badge readers</b>: cameras monitor but do not grant or deny entry.</span><span class='qd'><b>To authenticate users to the domain</b>: that is the job of a directory service, not a camera.</span>" },
{ id:"D2-015", domain:2, obj:"2.1", diff:"easy", q:"Which biometric method scans the unique pattern of ridges on a fingertip to authenticate a user?", options:["Fingerprint reader","Smart card","RFID badge","Cable lock"], answer:0, explain:"<strong>Fingerprint reader</strong> is correct because it captures and matches the user's fingerprint, a 'something you are' factor.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Smart card</b>: a 'something you have' physical token, not biometric.</span><span class='qd'><b>RFID badge</b>: also 'something you have' and not biometric.</span><span class='qd'><b>Cable lock</b>: physical theft deterrent, not authentication.</span>" },
{ id:"D2-016", domain:2, obj:"2.2", diff:"easy", q:"Which wireless security standard is the most current and secure for protecting a Wi-Fi network?", options:["WEP","WPA","WPA2","WPA3"], answer:3, explain:"<strong>WPA3</strong> is correct because it is the newest Wi-Fi security protocol, offering stronger encryption and protection against offline password guessing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>WEP</b>: an obsolete, easily cracked standard.</span><span class='qd'><b>WPA</b>: improved on WEP but is now outdated.</span><span class='qd'><b>WPA2</b>: strong but superseded by WPA3.</span>" },
{ id:"D2-017", domain:2, obj:"2.2", diff:"medium", q:"WPA2 introduced which encryption cipher as a stronger replacement for the weaker TKIP used in WPA?", options:["AES","RC4","DES","MD5"], answer:0, explain:"<strong>AES</strong> is correct because WPA2 uses AES with CCMP, providing robust encryption far stronger than TKIP.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RC4</b>: the weak stream cipher used by WEP and TKIP.</span><span class='qd'><b>DES</b>: an old block cipher not used by WPA2.</span><span class='qd'><b>MD5</b>: a hashing algorithm, not an encryption cipher.</span>" },
{ id:"D2-018", domain:2, obj:"2.2", diff:"medium", q:"An enterprise wants each Wi-Fi user to authenticate with their own domain credentials against a central server rather than a shared passphrase. Which protocol provides this AAA service?", options:["WPS","RADIUS","NAT","DHCP"], answer:1, explain:"<strong>RADIUS</strong> is correct because it provides centralized authentication, authorization, and accounting so users log in with individual credentials (WPA2/WPA3 Enterprise).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>WPS</b>: a push-button setup feature, not centralized authentication.</span><span class='qd'><b>NAT</b>: translates IP addresses; not authentication.</span><span class='qd'><b>DHCP</b>: assigns IP addresses; not authentication.</span>" },
{ id:"D2-019", domain:2, obj:"2.2", diff:"hard", q:"Which AAA protocol, developed by Cisco, separates authentication, authorization, and accounting into independent processes and encrypts the entire payload?", options:["RADIUS","TACACS+","Kerberos","LDAP"], answer:1, explain:"<strong>TACACS+</strong> is correct because it decouples AAA functions and encrypts the full packet body, commonly used for network device administration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RADIUS</b>: combines authentication and authorization and only encrypts the password, not the whole payload.</span><span class='qd'><b>Kerberos</b>: a ticket-based authentication protocol, not a network-admin AAA framework.</span><span class='qd'><b>LDAP</b>: a directory access protocol, not an AAA accounting protocol.</span>" },
{ id:"D2-020", domain:2, obj:"2.2", diff:"medium", q:"Which authentication protocol used by Active Directory issues time-sensitive tickets and relies on a Key Distribution Center?", options:["Kerberos","RADIUS","TACACS+","WPA3"], answer:0, explain:"<strong>Kerberos</strong> is correct because it uses a KDC to grant tickets that prove identity without resending passwords, and tickets are time-stamped.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RADIUS</b>: centralized AAA for network access, not the AD ticket system.</span><span class='qd'><b>TACACS+</b>: AAA for device administration.</span><span class='qd'><b>WPA3</b>: a wireless encryption standard, not a ticket protocol.</span>" },
{ id:"D2-021", domain:2, obj:"2.2", diff:"easy", q:"Which legacy wireless protocol should be disabled because its weak 24-bit initialization vector makes it trivially crackable?", options:["WPA3","WPA2","WEP","AES"], answer:2, explain:"<strong>WEP</strong> is correct because its short, reused initialization vectors allow attackers to recover the key quickly, so it is considered insecure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>WPA3</b>: the current secure standard.</span><span class='qd'><b>WPA2</b>: still strong when using AES.</span><span class='qd'><b>AES</b>: a strong encryption cipher, not a vulnerable protocol.</span>" },
{ id:"D2-022", domain:2, obj:"2.2", diff:"hard", q:"A technician configures a wireless network for WPA2-Enterprise. Which two components must be present compared to WPA2-Personal?", options:["A pre-shared key only","A RADIUS server and individual user accounts","WPS and a guest VLAN","MAC filtering and SSID hiding"], answer:1, explain:"<strong>A RADIUS server and individual user accounts</strong> is correct because Enterprise mode uses 802.1X with a RADIUS server so each user authenticates separately instead of sharing one passphrase.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A pre-shared key only</b>: that describes Personal mode, not Enterprise.</span><span class='qd'><b>WPS and a guest VLAN</b>: convenience/segmentation features, not the defining Enterprise components.</span><span class='qd'><b>MAC filtering and SSID hiding</b>: minor SOHO measures, not Enterprise authentication.</span>" },
{ id:"D2-023", domain:2, obj:"2.2", diff:"medium", q:"TKIP improved on WEP but is now deprecated. What was TKIP's main weakness that AES addressed?", options:["It still relied on the weak RC4 cipher","It used 256-bit keys","It required a RADIUS server","It only worked on 5 GHz networks"], answer:0, explain:"<strong>It still relied on the weak RC4 cipher</strong> is correct because TKIP wrapped per-packet keying around RC4, which remained vulnerable, so AES/CCMP replaced it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It used 256-bit keys</b>: TKIP did not provide stronger keys; that is not its weakness.</span><span class='qd'><b>It required a RADIUS server</b>: TKIP works in personal mode without RADIUS.</span><span class='qd'><b>It only worked on 5 GHz networks</b>: band has nothing to do with TKIP's weakness.</span>" },
{ id:"D2-024", domain:2, obj:"2.2", diff:"easy", q:"What does the acronym AAA describe in the context of network security protocols like RADIUS and TACACS+?", options:["Authentication, Authorization, and Accounting","Access, Audit, and Alerting","Allocation, Assignment, and Addressing","Authentication, Auditing, and Archiving"], answer:0, explain:"<strong>Authentication, Authorization, and Accounting</strong> is correct because AAA frameworks verify identity, grant permissions, and log activity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Access, Audit, and Alerting</b>: not the standard AAA expansion.</span><span class='qd'><b>Allocation, Assignment, and Addressing</b>: relates to addressing, not AAA.</span><span class='qd'><b>Authentication, Auditing, and Archiving</b>: a plausible-sounding but incorrect expansion.</span>" },
{ id:"D2-025", domain:2, obj:"2.2", diff:"hard", q:"WPA3-Personal replaces the WPA2 four-way handshake with which mechanism to resist offline dictionary attacks?", options:["Simultaneous Authentication of Equals (SAE)","WPS PIN exchange","Open System authentication","Shared Key authentication"], answer:0, explain:"<strong>Simultaneous Authentication of Equals (SAE)</strong> is correct because SAE performs a secure password-based key exchange that prevents attackers from capturing a handshake and cracking it offline.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>WPS PIN exchange</b>: a vulnerable setup method, not the WPA3 handshake.</span><span class='qd'><b>Open System authentication</b>: provides no security at all.</span><span class='qd'><b>Shared Key authentication</b>: a weak WEP-era method.</span>" },
{ id:"D2-026", domain:2, obj:"2.3", diff:"easy", q:"Which type of malware self-replicates and spreads across networks without needing a host file or user action?", options:["Worm","Trojan","Spyware","Keylogger"], answer:0, explain:"<strong>Worm</strong> is correct because a worm propagates by itself through networks, consuming bandwidth and resources without attaching to a file.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trojan</b>: disguises itself as legitimate software and does not self-replicate.</span><span class='qd'><b>Spyware</b>: secretly collects information; it does not self-spread like a worm.</span><span class='qd'><b>Keylogger</b>: records keystrokes; not a self-replicating spreader.</span>" },
{ id:"D2-027", domain:2, obj:"2.3", diff:"easy", q:"Malware that encrypts a victim's files and demands payment for the decryption key is known as what?", options:["Rootkit","Ransomware","Adware","Worm"], answer:1, explain:"<strong>Ransomware</strong> is correct because it locks or encrypts data and extorts the user for payment to restore access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rootkit</b>: hides itself and grants stealthy privileged access; it does not extort by encryption.</span><span class='qd'><b>Adware</b>: displays unwanted ads.</span><span class='qd'><b>Worm</b>: self-replicates across networks but does not necessarily encrypt for ransom.</span>" },
{ id:"D2-028", domain:2, obj:"2.3", diff:"medium", q:"Which malware embeds itself deep in the operating system or firmware to hide its presence and maintain privileged control?", options:["Rootkit","Adware","Trojan","Cryptominer"], answer:0, explain:"<strong>Rootkit</strong> is correct because it operates at a low level (kernel or firmware) to conceal itself and other malware while retaining administrative control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Adware</b>: shows ads and is not designed for deep stealth.</span><span class='qd'><b>Trojan</b>: masquerades as legitimate software but does not inherently hide at the kernel level.</span><span class='qd'><b>Cryptominer</b>: uses CPU/GPU to mine currency, not primarily to hide control.</span>" },
{ id:"D2-029", domain:2, obj:"2.3", diff:"medium", q:"A program records every key a user presses to capture passwords and messages. What is it?", options:["Keylogger","Boot sector virus","Worm","Rootkit"], answer:0, explain:"<strong>Keylogger</strong> is correct because it logs keystrokes to steal credentials and other typed information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Boot sector virus</b>: infects the boot record, not keystrokes.</span><span class='qd'><b>Worm</b>: self-replicates across networks.</span><span class='qd'><b>Rootkit</b>: hides privileged access rather than logging keys.</span>" },
{ id:"D2-030", domain:2, obj:"2.3", diff:"hard", q:"A workstation's CPU runs at 100% constantly, fans are loud, and performance is poor, yet no foreground programs explain it. Which malware is the most likely cause?", options:["Cryptominer","Adware","Boot sector virus","Spyware"], answer:0, explain:"<strong>Cryptominer</strong> is correct because cryptomining malware hijacks processor and GPU cycles to mine cryptocurrency, causing sustained high utilization and heat.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Adware</b>: produces ads rather than maxing the CPU.</span><span class='qd'><b>Boot sector virus</b>: interferes with startup, not constant CPU load.</span><span class='qd'><b>Spyware</b>: quietly collects data and does not typically peg the CPU.</span>" },
{ id:"D2-031", domain:2, obj:"2.3", diff:"medium", q:"Which malware disguises itself as a useful or legitimate application to trick a user into installing it, then performs malicious actions?", options:["Trojan","Worm","Boot sector virus","Logic bomb"], answer:0, explain:"<strong>Trojan</strong> is correct because a Trojan horse appears to be desirable software but carries a hidden malicious payload.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Worm</b>: spreads automatically and does not rely on disguise.</span><span class='qd'><b>Boot sector virus</b>: infects the boot record rather than posing as an app.</span><span class='qd'><b>Logic bomb</b>: triggers on a condition and is not defined by disguising itself as a program.</span>" },
{ id:"D2-032", domain:2, obj:"2.3", diff:"hard", q:"A technician suspects a deeply embedded rootkit on a Windows PC that anti-malware cannot fully remove while Windows is running. Which approach is the most reliable remediation?", options:["Run a quick scan in normal mode","Back up data, then wipe and reinstall the OS from trusted media","Disable the antivirus and reboot","Clear the browser cache"], answer:1, explain:"<strong>Back up data, then wipe and reinstall the OS from trusted media</strong> is correct because a stubborn rootkit may persist below the OS, so a clean reinstall is often the only assured fix after preserving data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Run a quick scan in normal mode</b>: a rootkit can hide from scanners while the infected OS is loaded.</span><span class='qd'><b>Disable the antivirus and reboot</b>: removes protection and does nothing to remove the rootkit.</span><span class='qd'><b>Clear the browser cache</b>: irrelevant to a kernel-level rootkit.</span>" },
{ id:"D2-033", domain:2, obj:"2.3", diff:"medium", q:"Within the CompTIA malware removal best practice steps, what should you do immediately after identifying and verifying symptoms of malware?", options:["Educate the end user","Quarantine the infected system","Schedule scans and run updates","Enable System Restore"], answer:1, explain:"<strong>Quarantine the infected system</strong> is correct because isolating the machine prevents the malware from spreading while you remediate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Educate the end user</b>: this is the final step, after cleanup.</span><span class='qd'><b>Schedule scans and run updates</b>: occurs later, after remediation.</span><span class='qd'><b>Enable System Restore</b>: you actually disable System Restore before remediation, not enable it.</span>" },
{ id:"D2-034", domain:2, obj:"2.3", diff:"medium", q:"During malware remediation on Windows, why should System Restore be disabled before cleaning the system?", options:["It frees up RAM for scanning","Restore points can harbor copies of the malware","It speeds up the antivirus engine","It encrypts the infected files"], answer:1, explain:"<strong>Restore points can harbor copies of the malware</strong> is correct because malware may be captured in restore points, allowing reinfection if restored, so you disable and purge them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It frees up RAM for scanning</b>: disabling System Restore does not allocate RAM.</span><span class='qd'><b>It speeds up the antivirus engine</b>: it has no meaningful effect on scan speed.</span><span class='qd'><b>It encrypts the infected files</b>: System Restore does not encrypt files.</span>" },
{ id:"D2-035", domain:2, obj:"2.3", diff:"easy", q:"Which Windows boot option loads a minimal set of drivers and services, useful for removing malware that interferes with normal startup?", options:["Safe Mode","Fast startup","Hibernation","Sleep mode"], answer:0, explain:"<strong>Safe Mode</strong> is correct because it starts Windows with only essential components, often preventing malware from loading so it can be removed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fast startup</b>: a hybrid shutdown feature that speeds boot, not a cleaning environment.</span><span class='qd'><b>Hibernation</b>: saves the session to disk and powers off.</span><span class='qd'><b>Sleep mode</b>: a low-power standby state.</span>" },
{ id:"D2-036", domain:2, obj:"2.3", diff:"hard", q:"After cleaning malware from a workstation, which two final best-practice steps remain to reduce the chance of recurrence?", options:["Re-enable and create a fresh restore point, then educate the user","Disconnect from the network permanently","Format every drive and reimage all peers","Disable Windows Update to avoid conflicts"], answer:0, explain:"<strong>Re-enable and create a fresh restore point, then educate the user</strong> is correct because CompTIA's steps finish by re-enabling System Restore with a clean restore point and educating the end user to prevent future infections.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disconnect from the network permanently</b>: impractical and unnecessary after cleanup.</span><span class='qd'><b>Format every drive and reimage all peers</b>: excessive when remediation succeeded.</span><span class='qd'><b>Disable Windows Update to avoid conflicts</b>: removes patches and increases risk.</span>" },
{ id:"D2-037", domain:2, obj:"2.3", diff:"easy", q:"Which type of malware secretly monitors user activity and gathers personal information without consent?", options:["Spyware","Worm","Trojan","Rootkit"], answer:0, explain:"<strong>Spyware</strong> is correct because it covertly tracks browsing, keystrokes, or other activity and reports the data to a third party.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Worm</b>: self-replicates across networks.</span><span class='qd'><b>Trojan</b>: poses as legitimate software.</span><span class='qd'><b>Rootkit</b>: hides privileged access at a low level.</span>" },
{ id:"D2-038", domain:2, obj:"2.3", diff:"medium", q:"A virus that infects the master boot record so it loads before the operating system is classified as what?", options:["Boot sector virus","Macro virus","Polymorphic worm","Adware"], answer:0, explain:"<strong>Boot sector virus</strong> is correct because it resides in the boot sector/MBR and executes during startup before the OS loads.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Macro virus</b>: hides in document macros, not the boot record.</span><span class='qd'><b>Polymorphic worm</b>: a self-spreading worm that changes its code; not specifically a boot record infector.</span><span class='qd'><b>Adware</b>: displays ads.</span>" },
{ id:"D2-039", domain:2, obj:"2.4", diff:"easy", q:"An attacker sends a mass email claiming to be from a bank, asking recipients to click a link and enter their credentials. What attack is this?", options:["Phishing","Tailgating","Shoulder surfing","DDoS"], answer:0, explain:"<strong>Phishing</strong> is correct because it uses fraudulent email messages to lure many users into revealing credentials or sensitive data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tailgating</b>: physically following someone through a secured door.</span><span class='qd'><b>Shoulder surfing</b>: watching over someone's shoulder to steal information.</span><span class='qd'><b>DDoS</b>: floods a service with traffic to deny access.</span>" },
{ id:"D2-040", domain:2, obj:"2.4", diff:"medium", q:"A targeted phishing attack aimed specifically at a company's CEO or other high-value executive is called what?", options:["Whaling","Vishing","Smishing","Pharming"], answer:0, explain:"<strong>Whaling</strong> is correct because it is spear phishing directed at senior, high-profile targets such as executives.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Vishing</b>: phishing conducted over voice/phone.</span><span class='qd'><b>Smishing</b>: phishing via SMS text messages.</span><span class='qd'><b>Pharming</b>: redirects users to fake sites via DNS poisoning.</span>" },
{ id:"D2-041", domain:2, obj:"2.4", diff:"easy", q:"A caller pretends to be IT support over the phone to trick an employee into revealing a password. This social engineering attack is known as what?", options:["Vishing","Phishing","Shoulder surfing","Dumpster diving"], answer:0, explain:"<strong>Vishing</strong> is correct because it is voice phishing, using phone calls to manipulate victims into divulging information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Phishing</b>: typically uses email rather than a live phone call.</span><span class='qd'><b>Shoulder surfing</b>: visually observing data entry.</span><span class='qd'><b>Dumpster diving</b>: searching trash for discarded information.</span>" },
{ id:"D2-042", domain:2, obj:"2.4", diff:"medium", q:"An attacker sets up a rogue access point that mimics a legitimate Wi-Fi network's SSID to intercept user traffic. What is this attack called?", options:["Evil twin","On-path attack","Brute force","SQL injection"], answer:0, explain:"<strong>Evil twin</strong> is correct because the attacker broadcasts a fraudulent access point using a trusted SSID so victims connect and expose data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>On-path attack</b>: intercepts traffic between two parties but is a broader category; the rogue AP is specifically an evil twin.</span><span class='qd'><b>Brute force</b>: guesses passwords repeatedly.</span><span class='qd'><b>SQL injection</b>: attacks a database through input fields.</span>" },
{ id:"D2-043", domain:2, obj:"2.4", diff:"easy", q:"Going through a company's garbage to find discarded documents containing sensitive information is which type of attack?", options:["Dumpster diving","Tailgating","Phishing","Spoofing"], answer:0, explain:"<strong>Dumpster diving</strong> is correct because attackers retrieve improperly discarded papers or media to gather useful intelligence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tailgating</b>: following someone through a secured entrance.</span><span class='qd'><b>Phishing</b>: fraudulent email to obtain credentials.</span><span class='qd'><b>Spoofing</b>: faking an identity such as an IP or email address.</span>" },
{ id:"D2-044", domain:2, obj:"2.4", diff:"medium", q:"Many compromised computers simultaneously flood a web server with traffic to make it unavailable. What attack is occurring?", options:["DDoS","Zero-day","Insider threat","XSS"], answer:0, explain:"<strong>DDoS</strong> is correct because a distributed denial-of-service uses many bots to overwhelm a target's resources and disrupt service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Zero-day</b>: exploits an unknown, unpatched vulnerability.</span><span class='qd'><b>Insider threat</b>: malicious or negligent action by someone inside the organization.</span><span class='qd'><b>XSS</b>: injects scripts into web pages viewed by others.</span>" },
{ id:"D2-045", domain:2, obj:"2.4", diff:"hard", q:"A vulnerability is exploited by attackers before the vendor is aware of it or has released a patch. What is this called?", options:["Zero-day attack","Brute-force attack","On-path attack","Replay attack"], answer:0, explain:"<strong>Zero-day attack</strong> is correct because it targets a previously unknown flaw for which no fix yet exists, giving defenders zero days to prepare.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Brute-force attack</b>: systematically guesses credentials.</span><span class='qd'><b>On-path attack</b>: intercepts communications between two parties.</span><span class='qd'><b>Replay attack</b>: captures and resends valid data to impersonate a user.</span>" },
{ id:"D2-046", domain:2, obj:"2.4", diff:"medium", q:"An attacker secretly positions themselves between a client and server to intercept and possibly alter the communication. What is this attack now commonly called?", options:["On-path attack","Phishing","Tailgating","Brute force"], answer:0, explain:"<strong>On-path attack</strong> is correct because it (formerly man-in-the-middle) places the attacker between two communicating parties to eavesdrop or modify data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Phishing</b>: tricks users via fraudulent messages.</span><span class='qd'><b>Tailgating</b>: a physical access attack.</span><span class='qd'><b>Brute force</b>: repeatedly guesses passwords.</span>" },
{ id:"D2-047", domain:2, obj:"2.4", diff:"easy", q:"Repeatedly trying many password combinations until the correct one is found describes which attack?", options:["Brute-force attack","Phishing","Dumpster diving","Spoofing"], answer:0, explain:"<strong>Brute-force attack</strong> is correct because it systematically attempts every possible combination to crack a credential.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Phishing</b>: deceives users into giving up credentials voluntarily.</span><span class='qd'><b>Dumpster diving</b>: searches discarded materials.</span><span class='qd'><b>Spoofing</b>: falsifies an identity.</span>" },
{ id:"D2-048", domain:2, obj:"2.4", diff:"hard", q:"A web form passes user input directly into a database query, allowing an attacker to enter ' OR '1'='1 and bypass login. Which attack is this?", options:["SQL injection","Cross-site scripting","DDoS","Evil twin"], answer:0, explain:"<strong>SQL injection</strong> is correct because unsanitized input is interpreted as part of the SQL command, letting the attacker manipulate the database.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cross-site scripting</b>: injects client-side scripts into pages viewed by other users, not database commands.</span><span class='qd'><b>DDoS</b>: floods a service rather than injecting queries.</span><span class='qd'><b>Evil twin</b>: a rogue wireless access point.</span>" },
{ id:"D2-049", domain:2, obj:"2.4", diff:"medium", q:"An attacker injects malicious JavaScript into a trusted website so that it runs in the browsers of other visitors. What attack is this?", options:["Cross-site scripting","SQL injection","On-path attack","Brute force"], answer:0, explain:"<strong>Cross-site scripting</strong> is correct because XSS embeds malicious client-side script in a web page that executes in victims' browsers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SQL injection</b>: targets the backend database, not the visitor's browser.</span><span class='qd'><b>On-path attack</b>: intercepts traffic between endpoints.</span><span class='qd'><b>Brute force</b>: guesses credentials.</span>" },
{ id:"D2-050", domain:2, obj:"2.4", diff:"medium", q:"A disgruntled employee with legitimate access deliberately leaks confidential data. This is best described as what?", options:["Insider threat","Zero-day attack","Evil twin","Phishing"], answer:0, explain:"<strong>Insider threat</strong> is correct because the danger comes from someone within the organization who has authorized access and misuses it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Zero-day attack</b>: exploits an unpatched flaw from outside knowledge.</span><span class='qd'><b>Evil twin</b>: a rogue access point.</span><span class='qd'><b>Phishing</b>: an external deception via messages.</span>" },
{ id:"D2-051", domain:2, obj:"2.4", diff:"easy", q:"An unauthorized person closely follows an employee through a badge-controlled door without scanning their own credential. What is this called?", options:["Tailgating","Shoulder surfing","Vishing","Pharming"], answer:0, explain:"<strong>Tailgating</strong> is correct because the intruder gains entry by piggybacking on an authorized person's access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Shoulder surfing</b>: visually stealing information.</span><span class='qd'><b>Vishing</b>: voice phishing over the phone.</span><span class='qd'><b>Pharming</b>: DNS redirection to fake sites.</span>" },
{ id:"D2-052", domain:2, obj:"2.4", diff:"medium", q:"Falsifying the source address of a packet or email so it appears to come from a trusted entity is which technique?", options:["Spoofing","Brute force","Dumpster diving","Whaling"], answer:0, explain:"<strong>Spoofing</strong> is correct because it forges an identifier such as an IP, MAC, or email address to impersonate a trusted source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Brute force</b>: guesses credentials.</span><span class='qd'><b>Dumpster diving</b>: searches trash for data.</span><span class='qd'><b>Whaling</b>: phishing aimed at executives.</span>" },
{ id:"D2-053", domain:2, obj:"2.4", diff:"hard", q:"Which combination of measures most directly reduces the success of shoulder surfing in a busy open office?", options:["Privacy screen filters and positioning monitors away from walkways","Stronger Wi-Fi encryption and MAC filtering","Daily full antivirus scans","Disabling AutoRun on USB devices"], answer:0, explain:"<strong>Privacy screen filters and positioning monitors away from walkways</strong> is correct because shoulder surfing is a visual attack, so limiting line of sight to the screen is the direct countermeasure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stronger Wi-Fi encryption and MAC filtering</b>: protects wireless traffic, not what is visible on screen.</span><span class='qd'><b>Daily full antivirus scans</b>: address malware, not visual snooping.</span><span class='qd'><b>Disabling AutoRun on USB devices</b>: blocks removable-media autorun, unrelated to shoulder surfing.</span>" },
{ id:"D2-054", domain:2, obj:"2.4", diff:"easy", q:"Watching someone enter their PIN at an ATM by looking over their shoulder is an example of which attack?", options:["Shoulder surfing","Tailgating","Phishing","DDoS"], answer:0, explain:"<strong>Shoulder surfing</strong> is correct because it is the act of observing a person's screen or keypad to capture sensitive information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Tailgating</b>: following someone through a secure door.</span><span class='qd'><b>Phishing</b>: deceptive messages to obtain data.</span><span class='qd'><b>DDoS</b>: overwhelms a service with traffic.</span>" },
{ id:"D2-055", domain:2, obj:"2.5", diff:"medium", q:"A user has Full Control via NTFS permissions on a folder but only Read via the share permission when accessing it over the network. What is their effective access from the network?", options:["Full Control","Modify","Read","No access"], answer:2, explain:"<strong>Read</strong> is correct because when NTFS and share permissions are combined over the network, the most restrictive of the two applies, which here is Read.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full Control</b>: that is only the NTFS level; the share caps it at Read.</span><span class='qd'><b>Modify</b>: not granted by either the more restrictive share or by simple combination.</span><span class='qd'><b>No access</b>: the user does have Read, so access is not fully denied.</span>" },
{ id:"D2-056", domain:2, obj:"2.5", diff:"medium", q:"Which Windows feature encrypts the entire system drive and can use a TPM to protect the keys?", options:["BitLocker","EFS","UAC","Windows Defender Firewall"], answer:0, explain:"<strong>BitLocker</strong> is correct because it provides full-volume encryption and integrates with the TPM to secure the encryption keys.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>EFS</b>: encrypts individual files/folders, not the whole volume with TPM.</span><span class='qd'><b>UAC</b>: prompts for elevation; it does not encrypt.</span><span class='qd'><b>Windows Defender Firewall</b>: filters network traffic.</span>" },
{ id:"D2-057", domain:2, obj:"2.5", diff:"easy", q:"Which Windows feature lets a user encrypt individual files and folders on an NTFS volume so only their account can open them?", options:["EFS","BitLocker","UAC","Compression"], answer:0, explain:"<strong>EFS</strong> is correct because the Encrypting File System encrypts specific files or folders tied to the user's certificate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>BitLocker</b>: encrypts entire volumes, not individual files.</span><span class='qd'><b>UAC</b>: controls privilege elevation prompts.</span><span class='qd'><b>Compression</b>: reduces file size; it does not encrypt.</span>" },
{ id:"D2-058", domain:2, obj:"2.5", diff:"medium", q:"What is the primary purpose of User Account Control (UAC) in Windows?", options:["To prompt for consent or credentials before allowing changes that require administrative privileges","To encrypt the system drive","To scan files for viruses","To manage Wi-Fi connections"], answer:0, explain:"<strong>To prompt for consent or credentials before allowing changes that require administrative privileges</strong> is correct because UAC limits standard processes and asks for elevation when an action needs admin rights.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To encrypt the system drive</b>: that is BitLocker's job.</span><span class='qd'><b>To scan files for viruses</b>: that is Microsoft Defender Antivirus.</span><span class='qd'><b>To manage Wi-Fi connections</b>: handled by network settings, not UAC.</span>" },
{ id:"D2-059", domain:2, obj:"2.5", diff:"hard", q:"A file is moved (not copied) to a different folder on the same NTFS volume. What happens to its NTFS permissions?", options:["It retains its original permissions","It inherits the destination folder's permissions","All permissions are removed","It becomes encrypted automatically"], answer:0, explain:"<strong>It retains its original permissions</strong> is correct because moving a file within the same NTFS volume keeps its existing explicit permissions rather than inheriting new ones.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It inherits the destination folder's permissions</b>: that happens when copying, or when moving to a different volume, not moving within the same volume.</span><span class='qd'><b>All permissions are removed</b>: permissions are not wiped by a move.</span><span class='qd'><b>It becomes encrypted automatically</b>: a move does not trigger encryption.</span>" },
{ id:"D2-060", domain:2, obj:"2.5", diff:"medium", q:"Which built-in Windows tool blocks or allows inbound and outbound network connections based on configured rules?", options:["Windows Defender Firewall","BitLocker","EFS","Task Scheduler"], answer:0, explain:"<strong>Windows Defender Firewall</strong> is correct because it filters traffic by rule, controlling which connections are permitted in and out of the system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>BitLocker</b>: encrypts drives.</span><span class='qd'><b>EFS</b>: encrypts files.</span><span class='qd'><b>Task Scheduler</b>: runs tasks on a schedule.</span>" },
{ id:"D2-061", domain:2, obj:"2.5", diff:"hard", q:"When NTFS and share permissions both apply to a network resource, how is the effective permission determined?", options:["The most restrictive of the combined NTFS and combined share permissions wins","The most permissive always wins","Share permissions always override NTFS","NTFS permissions are ignored over the network"], answer:0, explain:"<strong>The most restrictive of the combined NTFS and combined share permissions wins</strong> is correct because Windows evaluates each set, then applies whichever cumulative result is more restrictive.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The most permissive always wins</b>: the opposite is true for the NTFS-vs-share comparison.</span><span class='qd'><b>Share permissions always override NTFS</b>: neither always overrides; the more restrictive applies.</span><span class='qd'><b>NTFS permissions are ignored over the network</b>: NTFS permissions still apply across the network.</span>" },
{ id:"D2-062", domain:2, obj:"2.5", diff:"easy", q:"Which Windows account type has the fewest privileges and cannot install most software or change system settings?", options:["Standard user","Administrator","Guest with full rights","Domain Admin"], answer:0, explain:"<strong>Standard user</strong> is correct because standard accounts can run applications and use the system but cannot make administrative changes, aligning with least privilege.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Administrator</b>: has full control over the system.</span><span class='qd'><b>Guest with full rights</b>: the Guest account is limited but the phrase 'full rights' is contradictory and incorrect.</span><span class='qd'><b>Domain Admin</b>: a highly privileged domain account.</span>" },
{ id:"D2-063", domain:2, obj:"2.5", diff:"medium", q:"To which Windows local group should a user be added so they can install software and manage all settings on a single PC?", options:["Administrators","Users","Guests","Backup Operators"], answer:0, explain:"<strong>Administrators</strong> is correct because members of the local Administrators group have full control over the computer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Users</b>: standard members with limited rights.</span><span class='qd'><b>Guests</b>: very limited, temporary access.</span><span class='qd'><b>Backup Operators</b>: can back up and restore files but not perform all administrative tasks.</span>" },
{ id:"D2-064", domain:2, obj:"2.6", diff:"easy", q:"Which workstation best practice sets a minimum length and complexity requirement that users must meet when choosing a password?", options:["Password policy","Screensaver delay","AutoPlay setting","Disk cleanup schedule"], answer:0, explain:"<strong>Password policy</strong> is correct because it enforces requirements like length, complexity, history, and expiration to strengthen credentials.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Screensaver delay</b>: relates to screen locking, not password rules.</span><span class='qd'><b>AutoPlay setting</b>: controls media autostart.</span><span class='qd'><b>Disk cleanup schedule</b>: manages storage, not credentials.</span>" },
{ id:"D2-065", domain:2, obj:"2.6", diff:"medium", q:"A technician wants to prevent an unauthorized person from booting a laptop from a USB drive or changing boot order. Which password should be configured?", options:["BIOS/UEFI password","Windows account password","Wi-Fi password","Screensaver password"], answer:0, explain:"<strong>BIOS/UEFI password</strong> is correct because a firmware password restricts access to setup and boot options before the OS loads.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Windows account password</b>: protects the OS login but does not control firmware boot settings.</span><span class='qd'><b>Wi-Fi password</b>: secures wireless access only.</span><span class='qd'><b>Screensaver password</b>: locks an active session, not the boot process.</span>" },
{ id:"D2-066", domain:2, obj:"2.6", diff:"medium", q:"Which workstation hardening step prevents malware from launching automatically when removable media is inserted?", options:["Disable AutoRun/AutoPlay","Enable fast startup","Increase the page file","Turn off the firewall"], answer:0, explain:"<strong>Disable AutoRun/AutoPlay</strong> is correct because turning off automatic execution stops malicious code on USB drives or discs from running without user action.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Enable fast startup</b>: speeds boot, no security benefit here.</span><span class='qd'><b>Increase the page file</b>: affects virtual memory, not autorun.</span><span class='qd'><b>Turn off the firewall</b>: reduces security rather than improving it.</span>" },
{ id:"D2-067", domain:2, obj:"2.6", diff:"hard", q:"Which account management practice ensures that when an employee leaves the company, they immediately lose access to all systems?", options:["Disable the account as part of the offboarding process","Lengthen the password expiration window","Add the account to the Administrators group","Enable AutoPlay for their workstation"], answer:0, explain:"<strong>Disable the account as part of the offboarding process</strong> is correct because promptly disabling (then later removing) the account revokes the former employee's access right away.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Lengthen the password expiration window</b>: keeps access active longer, the opposite of the goal.</span><span class='qd'><b>Add the account to the Administrators group</b>: grants more access, not less.</span><span class='qd'><b>Enable AutoPlay for their workstation</b>: unrelated to revoking access.</span>" },
{ id:"D2-068", domain:2, obj:"2.6", diff:"easy", q:"Configuring a workstation to automatically lock and require a password after a few minutes of inactivity is an example of which best practice?", options:["Screen lock timeout","Disabling AutoRun","Changing default credentials","Firmware update"], answer:0, explain:"<strong>Screen lock timeout</strong> is correct because an automatic lock after inactivity prevents unauthorized use of an unattended session.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disabling AutoRun</b>: stops media autostart, a different control.</span><span class='qd'><b>Changing default credentials</b>: replaces factory passwords, not session locking.</span><span class='qd'><b>Firmware update</b>: patches device software, unrelated to inactivity locks.</span>" },
{ id:"D2-069", domain:2, obj:"2.6", diff:"medium", q:"Why should standard daily-use accounts be configured without administrative rights as a workstation best practice?", options:["To enforce least privilege and limit the impact of malware","To make logins faster","To allow more software to install automatically","To disable the firewall by default"], answer:0, explain:"<strong>To enforce least privilege and limit the impact of malware</strong> is correct because running as a standard user means malware or mistakes cannot easily make system-wide changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make logins faster</b>: privilege level does not affect login speed.</span><span class='qd'><b>To allow more software to install automatically</b>: standard accounts restrict, not enable, installs.</span><span class='qd'><b>To disable the firewall by default</b>: account type does not disable the firewall.</span>" },
{ id:"D2-070", domain:2, obj:"2.6", diff:"hard", q:"A company wants to ensure shared computers do not retain a previous user's logged-in session after they walk away. Which two settings best support this?", options:["Short screen lock timeout and requiring sign-out or auto sign-out policies","Enabling AutoPlay and Guest access","Disabling UAC and the firewall","Extending password expiration and enabling autorun"], answer:0, explain:"<strong>Short screen lock timeout and requiring sign-out or auto sign-out policies</strong> is correct because locking quickly and forcing sign-out prevents the next person from using a lingering session.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Enabling AutoPlay and Guest access</b>: increases risk and does not address lingering sessions.</span><span class='qd'><b>Disabling UAC and the firewall</b>: weakens security.</span><span class='qd'><b>Extending password expiration and enabling autorun</b>: neither addresses unattended sessions.</span>" },
{ id:"D2-071", domain:2, obj:"2.6", diff:"medium", q:"Which password policy setting prevents users from immediately reusing their previous passwords?", options:["Password history (enforce password history)","Minimum password length","Account lockout threshold","Maximum session length"], answer:0, explain:"<strong>Password history (enforce password history)</strong> is correct because it remembers prior passwords and blocks their reuse for a configured number of changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Minimum password length</b>: sets length, not reuse.</span><span class='qd'><b>Account lockout threshold</b>: locks accounts after failed attempts.</span><span class='qd'><b>Maximum session length</b>: limits how long a session lasts, not reuse.</span>" },
{ id:"D2-072", domain:2, obj:"2.6", diff:"easy", q:"Which best practice protects against attackers using widely known factory-set credentials on a new device?", options:["Change default usernames and passwords","Enable AutoRun","Disable the screensaver","Lower the UAC level"], answer:0, explain:"<strong>Change default usernames and passwords</strong> is correct because default credentials are publicly documented and must be replaced to secure the device.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Enable AutoRun</b>: increases risk of media-based malware.</span><span class='qd'><b>Disable the screensaver</b>: removes a session-lock safeguard.</span><span class='qd'><b>Lower the UAC level</b>: weakens privilege protection.</span>" },
{ id:"D2-073", domain:2, obj:"2.7", diff:"easy", q:"Which mobile device feature requires a fingerprint or facial scan to unlock the phone?", options:["Biometric screen lock","Remote wipe","Airplane mode","Bluetooth tethering"], answer:0, explain:"<strong>Biometric screen lock</strong> is correct because it uses a physical characteristic such as a fingerprint or face to authenticate and unlock the device.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Remote wipe</b>: erases a lost device remotely; it is not an unlock method.</span><span class='qd'><b>Airplane mode</b>: disables radios.</span><span class='qd'><b>Bluetooth tethering</b>: shares a data connection.</span>" },
{ id:"D2-074", domain:2, obj:"2.7", diff:"medium", q:"An employee's phone is lost with sensitive company data on it. Which feature lets the company erase all data on the device remotely?", options:["Remote wipe","Screen lock","Wi-Fi calling","Do Not Disturb"], answer:0, explain:"<strong>Remote wipe</strong> is correct because it remotely deletes the device's data to prevent exposure if the phone cannot be recovered.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Screen lock</b>: deters casual access but does not erase data remotely.</span><span class='qd'><b>Wi-Fi calling</b>: routes calls over Wi-Fi.</span><span class='qd'><b>Do Not Disturb</b>: silences notifications.</span>" },
{ id:"D2-075", domain:2, obj:"2.7", diff:"medium", q:"What is the main difference between MDM and MAM in mobile security?", options:["MDM manages the entire device while MAM manages only specific applications and their data","MDM only works on iOS while MAM only works on Android","MDM encrypts files and MAM manages Wi-Fi","MDM is hardware and MAM is firmware"], answer:0, explain:"<strong>MDM manages the entire device while MAM manages only specific applications and their data</strong> is correct because Mobile Device Management controls the whole device, whereas Mobile Application Management scopes control to managed apps, useful for BYOD.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>MDM only works on iOS while MAM only works on Android</b>: both work across platforms.</span><span class='qd'><b>MDM encrypts files and MAM manages Wi-Fi</b>: not the defining distinction.</span><span class='qd'><b>MDM is hardware and MAM is firmware</b>: both are software management approaches.</span>" },
{ id:"D2-076", domain:2, obj:"2.7", diff:"hard", q:"A BYOD program must protect corporate email and apps without controlling employees' personal data on their phones. Which solution best fits?", options:["Mobile Application Management (MAM) with containerization","Full device remote wipe on every sync","Disabling all biometrics","Requiring users to remove personal apps"], answer:0, explain:"<strong>Mobile Application Management (MAM) with containerization</strong> is correct because it secures and isolates corporate apps and data in a managed container while leaving personal content untouched.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full device remote wipe on every sync</b>: would erase personal data, unacceptable for BYOD.</span><span class='qd'><b>Disabling all biometrics</b>: reduces convenient security without solving data separation.</span><span class='qd'><b>Requiring users to remove personal apps</b>: defeats the purpose of BYOD.</span>" },
{ id:"D2-077", domain:2, obj:"2.7", diff:"easy", q:"Which security concern is specifically associated with IoT devices like smart thermostats and cameras on a home network?", options:["They often ship with weak default credentials and infrequent firmware updates","They always use WPA3 by default","They cannot connect to networks","They are immune to malware"], answer:0, explain:"<strong>They often ship with weak default credentials and infrequent firmware updates</strong> is correct because many IoT devices have poor security defaults and limited patching, making them common attack targets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They always use WPA3 by default</b>: many IoT devices lag on modern standards.</span><span class='qd'><b>They cannot connect to networks</b>: connectivity is their entire purpose.</span><span class='qd'><b>They are immune to malware</b>: IoT devices are frequently compromised.</span>" },
{ id:"D2-078", domain:2, obj:"2.7", diff:"medium", q:"On a managed mobile device, what is a configuration profile used for?", options:["To deploy settings such as Wi-Fi, VPN, email, and restrictions to the device","To increase battery capacity","To physically lock the SIM tray","To overclock the processor"], answer:0, explain:"<strong>To deploy settings such as Wi-Fi, VPN, email, and restrictions to the device</strong> is correct because profiles push standardized, enforceable configuration to managed devices.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To increase battery capacity</b>: software profiles cannot change battery hardware.</span><span class='qd'><b>To physically lock the SIM tray</b>: that is a hardware action.</span><span class='qd'><b>To overclock the processor</b>: profiles do not change clock speeds.</span>" },
{ id:"D2-079", domain:2, obj:"2.7", diff:"hard", q:"A security policy requires that failed unlock attempts on a phone eventually erase the device. Which feature combination achieves this on a managed device?", options:["A screen lock with a failed-attempt limit tied to automatic data wipe","Disabling the screen lock and enabling tethering","Remote backup only with no lock","Airplane mode after each failure"], answer:0, explain:"<strong>A screen lock with a failed-attempt limit tied to automatic data wipe</strong> is correct because configuring the device to wipe after a set number of failed unlock attempts protects data against brute-force unlocking.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disabling the screen lock and enabling tethering</b>: removes the protection entirely.</span><span class='qd'><b>Remote backup only with no lock</b>: backups do not stop unauthorized access.</span><span class='qd'><b>Airplane mode after each failure</b>: does not erase data or prevent further attempts.</span>" },
{ id:"D2-080", domain:2, obj:"2.7", diff:"easy", q:"Which method unlocks a phone by recognizing the geometry of the user's face?", options:["Facial recognition","PIN","Pattern","Remote wipe"], answer:0, explain:"<strong>Facial recognition</strong> is correct because it is a biometric method that authenticates based on facial features.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>PIN</b>: a knowledge factor, not biometric.</span><span class='qd'><b>Pattern</b>: a swipe pattern, also knowledge-based.</span><span class='qd'><b>Remote wipe</b>: erases data and is not an unlock method.</span>" },
{ id:"D2-081", domain:2, obj:"2.7", diff:"medium", q:"Why is full-device encryption important on smartphones that store corporate data?", options:["If the device is lost, the data remains unreadable without the unlock credential","It speeds up app installation","It increases screen brightness","It disables the microphone"], answer:0, explain:"<strong>If the device is lost, the data remains unreadable without the unlock credential</strong> is correct because encryption protects stored data so a thief cannot read it without authentication.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It speeds up app installation</b>: encryption does not improve install speed.</span><span class='qd'><b>It increases screen brightness</b>: unrelated to encryption.</span><span class='qd'><b>It disables the microphone</b>: encryption does not control the mic.</span>" },
{ id:"D2-082", domain:2, obj:"2.8", diff:"easy", q:"Which physical data destruction method uses powerful magnets to scramble the data on a magnetic hard drive?", options:["Degaussing","Shredding","Drilling","Standard format"], answer:0, explain:"<strong>Degaussing</strong> is correct because a degausser applies a strong magnetic field that destroys the data and renders a magnetic HDD unusable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Shredding</b>: physically tears the drive apart rather than using magnetism.</span><span class='qd'><b>Drilling</b>: punches holes through platters but is not magnetic.</span><span class='qd'><b>Standard format</b>: only prepares the file system; data can be recovered.</span>" },
{ id:"D2-083", domain:2, obj:"2.8", diff:"medium", q:"Why is a standard (quick) format considered insufficient for securely disposing of a drive with confidential data?", options:["It removes file system pointers but leaves the underlying data recoverable","It physically destroys the platters","It encrypts the data permanently","It degausses the drive"], answer:0, explain:"<strong>It removes file system pointers but leaves the underlying data recoverable</strong> is correct because a standard format does not overwrite the actual data, so recovery tools can often retrieve it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It physically destroys the platters</b>: formatting is software, not physical destruction.</span><span class='qd'><b>It encrypts the data permanently</b>: formatting does not encrypt.</span><span class='qd'><b>It degausses the drive</b>: degaussing is a separate magnetic method.</span>" },
{ id:"D2-084", domain:2, obj:"2.8", diff:"medium", q:"A company must verify and document that a third-party vendor properly destroyed retired drives. Which document provides this assurance?", options:["Certificate of destruction","End-user license agreement","Acceptable use policy","Service level agreement"], answer:0, explain:"<strong>Certificate of destruction</strong> is correct because it is the formal record proving that media was destroyed according to policy, supporting compliance and chain of custody.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>End-user license agreement</b>: governs software use.</span><span class='qd'><b>Acceptable use policy</b>: defines proper system usage.</span><span class='qd'><b>Service level agreement</b>: defines service performance terms, not destruction proof.</span>" },
{ id:"D2-085", domain:2, obj:"2.8", diff:"hard", q:"An organization must sanitize SSDs for reuse internally while guaranteeing data cannot be recovered, without physically destroying them. Which method is most appropriate?", options:["Secure erase or cryptographic erase supported by the drive","Degaussing the SSD","Quick format","Deleting files and emptying the recycle bin"], answer:0, explain:"<strong>Secure erase or cryptographic erase supported by the drive</strong> is correct because SSDs respond to ATA Secure Erase / crypto-erase commands that purge data while keeping the drive usable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Degaussing the SSD</b>: degaussing affects magnetic media and does not erase flash memory.</span><span class='qd'><b>Quick format</b>: leaves data recoverable.</span><span class='qd'><b>Deleting files and emptying the recycle bin</b>: only removes references, not the data.</span>" },
{ id:"D2-086", domain:2, obj:"2.8", diff:"easy", q:"Which destruction method physically cuts a hard drive into small pieces using industrial machinery?", options:["Shredding","Standard format","Low-level format","Recycling intact"], answer:0, explain:"<strong>Shredding</strong> is correct because a hard drive shredder mechanically tears the media into fragments, making data recovery infeasible.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Standard format</b>: a software operation that leaves data recoverable.</span><span class='qd'><b>Low-level format</b>: overwrites at a low level but is not physical shredding.</span><span class='qd'><b>Recycling intact</b>: recycling a working drive without destruction risks data exposure.</span>" },
{ id:"D2-087", domain:2, obj:"2.8", diff:"medium", q:"Drilling holes through a hard drive's platters is an example of which category of data sanitization?", options:["Physical destruction","Cryptographic erase","Logical formatting","Overwriting"], answer:0, explain:"<strong>Physical destruction</strong> is correct because drilling damages the platters so the drive can no longer be read, a form of physical destruction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cryptographic erase</b>: destroys encryption keys via software, not by drilling.</span><span class='qd'><b>Logical formatting</b>: a software file-system operation.</span><span class='qd'><b>Overwriting</b>: writes patterns over data, not a physical method.</span>" },
{ id:"D2-088", domain:2, obj:"2.8", diff:"hard", q:"A hospital must dispose of drives that held protected health information and requires the highest assurance of irrecoverability before recycling the materials. Which approach best meets this?", options:["Physically destroy the media (shred or incinerate) and obtain a certificate of destruction","Perform a single quick format","Move files to the recycle bin and delete","Rename the partition and reuse the drive"], answer:0, explain:"<strong>Physically destroy the media (shred or incinerate) and obtain a certificate of destruction</strong> is correct because physical destruction with documented proof gives the strongest compliance assurance for highly sensitive data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Perform a single quick format</b>: leaves data recoverable.</span><span class='qd'><b>Move files to the recycle bin and delete</b>: trivially recoverable.</span><span class='qd'><b>Rename the partition and reuse the drive</b>: does not remove the data at all.</span>" },
{ id:"D2-089", domain:2, obj:"2.8", diff:"easy", q:"Which method destroys media by burning it completely?", options:["Incineration","Degaussing","Formatting","Defragmenting"], answer:0, explain:"<strong>Incineration</strong> is correct because burning the media destroys it physically so no data can be recovered.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Degaussing</b>: uses magnetism, not fire.</span><span class='qd'><b>Formatting</b>: a software process.</span><span class='qd'><b>Defragmenting</b>: reorganizes files for performance, not destruction.</span>" },
{ id:"D2-090", domain:2, obj:"2.9", diff:"easy", q:"What is the first thing a technician should change after installing a new SOHO router to secure it?", options:["The default administrator username and password","The DNS server only","The Ethernet cable","The router's physical color"], answer:0, explain:"<strong>The default administrator username and password</strong> is correct because default credentials are publicly known and must be replaced to prevent unauthorized configuration access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The DNS server only</b>: helpful but not the primary first hardening step.</span><span class='qd'><b>The Ethernet cable</b>: irrelevant to security configuration.</span><span class='qd'><b>The router's physical color</b>: cosmetic and irrelevant.</span>" },
{ id:"D2-091", domain:2, obj:"2.9", diff:"medium", q:"Which SOHO feature restricts wireless access to only devices whose hardware addresses are on an approved list?", options:["MAC filtering","Port forwarding","SSID broadcast","UPnP"], answer:0, explain:"<strong>MAC filtering</strong> is correct because it permits or denies devices based on their MAC addresses, adding a basic access restriction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Port forwarding</b>: directs inbound traffic to an internal host.</span><span class='qd'><b>SSID broadcast</b>: advertises the network name.</span><span class='qd'><b>UPnP</b>: lets devices auto-configure port mappings.</span>" },
{ id:"D2-092", domain:2, obj:"2.9", diff:"medium", q:"Disabling SSID broadcast on a SOHO router has which effect?", options:["The network name is not advertised, so it does not appear in casual scans","It encrypts all traffic with AES","It blocks all wireless clients","It assigns static IP addresses"], answer:0, explain:"<strong>The network name is not advertised, so it does not appear in casual scans</strong> is correct because hiding the SSID stops the router from broadcasting its name, though determined attackers can still detect it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It encrypts all traffic with AES</b>: encryption is set by WPA2/WPA3, not SSID hiding.</span><span class='qd'><b>It blocks all wireless clients</b>: clients can still connect if they know the name.</span><span class='qd'><b>It assigns static IP addresses</b>: that is unrelated addressing configuration.</span>" },
{ id:"D2-093", domain:2, obj:"2.9", diff:"hard", q:"A user hosts a game server on an internal PC at 192.168.1.50 and needs internet players to reach it on TCP 25565. Which SOHO router feature should be configured?", options:["Port forwarding to 192.168.1.50 on TCP 25565","Disabling the SSID broadcast","Enabling MAC filtering","Lowering the content filter"], answer:0, explain:"<strong>Port forwarding to 192.168.1.50 on TCP 25565</strong> is correct because port forwarding directs inbound traffic on a specified port to the designated internal host.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disabling the SSID broadcast</b>: hides the Wi-Fi name and does nothing for inbound game traffic.</span><span class='qd'><b>Enabling MAC filtering</b>: limits local device access, not external reachability.</span><span class='qd'><b>Lowering the content filter</b>: adjusts web filtering, unrelated to the port.</span>" },
{ id:"D2-094", domain:2, obj:"2.9", diff:"medium", q:"Why should SOHO router firmware be kept up to date?", options:["Updates patch security vulnerabilities and may add protections","It increases the antenna size","It changes the router's MAC address","It removes the need for a password"], answer:0, explain:"<strong>Updates patch security vulnerabilities and may add protections</strong> is correct because firmware updates fix known flaws that attackers could exploit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It increases the antenna size</b>: firmware cannot change hardware.</span><span class='qd'><b>It changes the router's MAC address</b>: not the purpose of an update.</span><span class='qd'><b>It removes the need for a password</b>: updates do not eliminate authentication needs.</span>" },
{ id:"D2-095", domain:2, obj:"2.9", diff:"easy", q:"Which SOHO feature blocks access to specific categories of websites, such as adult or gambling sites?", options:["Content filtering","Port forwarding","DHCP reservation","SSID hiding"], answer:0, explain:"<strong>Content filtering</strong> is correct because it inspects and blocks web traffic based on configured categories or URLs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Port forwarding</b>: routes inbound traffic to internal hosts.</span><span class='qd'><b>DHCP reservation</b>: assigns a fixed IP to a device.</span><span class='qd'><b>SSID hiding</b>: stops broadcasting the network name.</span>" },
{ id:"D2-096", domain:2, obj:"2.9", diff:"hard", q:"A small business wants public-facing servers reachable from the internet while keeping the internal LAN isolated from those servers. Which SOHO configuration best accomplishes this?", options:["Place the public servers in a DMZ/screened subnet","Put all devices on the same flat network","Disable the firewall entirely","Enable WPS for easy connections"], answer:0, explain:"<strong>Place the public servers in a DMZ/screened subnet</strong> is correct because a DMZ isolates internet-facing servers from the internal LAN, limiting exposure if those servers are compromised.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Put all devices on the same flat network</b>: removes isolation and increases risk.</span><span class='qd'><b>Disable the firewall entirely</b>: exposes everything to the internet.</span><span class='qd'><b>Enable WPS for easy connections</b>: a wireless setup feature unrelated to server isolation, and it is itself insecure.</span>" },
{ id:"D2-097", domain:2, obj:"2.9", diff:"medium", q:"Which built-in SOHO router capability inspects and controls traffic between the internal network and the internet based on rules?", options:["Firewall","DHCP","NAT loopback","SSID"], answer:0, explain:"<strong>Firewall</strong> is correct because the router's firewall enforces rules to permit or block traffic between the LAN and the internet.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DHCP</b>: assigns IP addresses to clients.</span><span class='qd'><b>NAT loopback</b>: lets internal clients reach internal servers via the public address.</span><span class='qd'><b>SSID</b>: the wireless network name.</span>" },
{ id:"D2-098", domain:2, obj:"2.9", diff:"easy", q:"Why is MAC filtering considered only a weak supplementary security measure on a SOHO network?", options:["Attackers can spoof an allowed MAC address","It encrypts traffic too strongly","It disables the firewall","It requires a RADIUS server"], answer:0, explain:"<strong>Attackers can spoof an allowed MAC address</strong> is correct because MAC addresses are easily discovered and forged, so filtering alone is not strong protection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It encrypts traffic too strongly</b>: MAC filtering does not encrypt anything.</span><span class='qd'><b>It disables the firewall</b>: it has no effect on the firewall.</span><span class='qd'><b>It requires a RADIUS server</b>: MAC filtering does not require RADIUS.</span>" },
{ id:"D2-099", domain:2, obj:"2.10", diff:"easy", q:"Which browser indicator shows that the connection to a website is encrypted with HTTPS?", options:["A padlock icon and an https:// address","A red battery icon","A green floppy disk icon","A blue gear icon"], answer:0, explain:"<strong>A padlock icon and an https:// address</strong> is correct because browsers display a padlock and the https scheme when the session uses TLS encryption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A red battery icon</b>: indicates power status, not encryption.</span><span class='qd'><b>A green floppy disk icon</b>: not a security indicator.</span><span class='qd'><b>A blue gear icon</b>: typically opens settings, not a security state.</span>" },
{ id:"D2-100", domain:2, obj:"2.10", diff:"medium", q:"Before installing a downloaded application, a technician compares the file's computed SHA-256 value with the one published by the vendor. What is this verifying?", options:["File integrity and authenticity","Network bandwidth","Screen resolution","Battery health"], answer:0, explain:"<strong>File integrity and authenticity</strong> is correct because matching the hash confirms the file was not altered or corrupted and came from the legitimate source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Network bandwidth</b>: hashing does not measure speed.</span><span class='qd'><b>Screen resolution</b>: unrelated to file hashing.</span><span class='qd'><b>Battery health</b>: unrelated to verifying a download.</span>" },
{ id:"D2-101", domain:2, obj:"2.10", diff:"medium", q:"Why should users install browser extensions only from official, trusted sources?", options:["Malicious extensions can steal data, inject ads, or hijack the browser","Trusted sources make pages load slower","Official sources disable HTTPS","Extensions from any source are always safe"], answer:0, explain:"<strong>Malicious extensions can steal data, inject ads, or hijack the browser</strong> is correct because untrusted extensions may contain malware or spyware with broad access to browsing activity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trusted sources make pages load slower</b>: source trust does not slow pages.</span><span class='qd'><b>Official sources disable HTTPS</b>: they do not disable encryption.</span><span class='qd'><b>Extensions from any source are always safe</b>: false, which is exactly why trusted sources matter.</span>" },
{ id:"D2-102", domain:2, obj:"2.10", diff:"easy", q:"Which browser tool securely stores and autofills strong, unique credentials so users do not reuse weak passwords?", options:["Password manager","Pop-up blocker","Cookie cleaner","Cache viewer"], answer:0, explain:"<strong>Password manager</strong> is correct because it generates, stores, and fills complex unique passwords, improving credential hygiene.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pop-up blocker</b>: blocks pop-up windows, not passwords.</span><span class='qd'><b>Cookie cleaner</b>: removes stored cookies.</span><span class='qd'><b>Cache viewer</b>: displays cached content.</span>" },
{ id:"D2-103", domain:2, obj:"2.10", diff:"hard", q:"A user visits an HTTPS site and the browser warns that the certificate is not trusted or has expired. What is the safest response?", options:["Do not proceed and verify the site or certificate before entering any data","Click through the warning and continue","Disable the browser's certificate checking","Add the site to the password manager"], answer:0, explain:"<strong>Do not proceed and verify the site or certificate before entering any data</strong> is correct because an invalid certificate may indicate an on-path attack or misconfiguration, so trust should be confirmed before continuing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Click through the warning and continue</b>: ignores a genuine security risk.</span><span class='qd'><b>Disable the browser's certificate checking</b>: removes a critical protection globally.</span><span class='qd'><b>Add the site to the password manager</b>: does nothing to address the certificate problem.</span>" },
{ id:"D2-104", domain:2, obj:"2.10", diff:"medium", q:"What does enabling private/incognito browsing do?", options:["It prevents the browser from saving local history, cookies, and form data for that session","It makes the user anonymous to all websites and ISPs","It encrypts all internet traffic like a VPN","It blocks all malware automatically"], answer:0, explain:"<strong>It prevents the browser from saving local history, cookies, and form data for that session</strong> is correct because private browsing limits what is stored locally, but it does not hide activity from sites or the network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the user anonymous to all websites and ISPs</b>: sites and ISPs can still see traffic.</span><span class='qd'><b>It encrypts all internet traffic like a VPN</b>: private mode does not provide VPN encryption.</span><span class='qd'><b>It blocks all malware automatically</b>: it offers no malware protection.</span>" },
{ id:"D2-105", domain:2, obj:"2.10", diff:"easy", q:"Which browser feature stops unwanted advertising windows from automatically opening?", options:["Pop-up blocker","Password manager","Bookmark bar","Reading mode"], answer:0, explain:"<strong>Pop-up blocker</strong> is correct because it prevents sites from spawning unsolicited pop-up or pop-under windows, reducing nuisance and some malvertising.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Password manager</b>: stores credentials.</span><span class='qd'><b>Bookmark bar</b>: holds saved links.</span><span class='qd'><b>Reading mode</b>: simplifies page layout.</span>" },
{ id:"D2-106", domain:2, obj:"2.10", diff:"medium", q:"What is the recommended best practice when obtaining software to install on a workstation?", options:["Download only from the official vendor site or a reputable, trusted source","Download from the first search result available","Use any free download mirror you find","Disable antivirus first so it does not interfere"], answer:0, explain:"<strong>Download only from the official vendor site or a reputable, trusted source</strong> is correct because trusted sources reduce the risk of bundled malware or tampered installers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Download from the first search result available</b>: search results can include malicious or impostor sites.</span><span class='qd'><b>Use any free download mirror you find</b>: unknown mirrors may distribute tampered files.</span><span class='qd'><b>Disable antivirus first so it does not interfere</b>: removing protection invites infection.</span>" },
{ id:"D2-107", domain:2, obj:"2.10", diff:"hard", q:"A website presents a valid certificate, but the domain in the address bar is slightly misspelled compared to the real bank. What threat is most likely?", options:["A typosquatting/phishing site using a legitimate certificate for a lookalike domain","An expired certificate","A DDoS attack","A boot sector virus"], answer:0, explain:"<strong>A typosquatting/phishing site using a legitimate certificate for a lookalike domain</strong> is correct because a valid certificate only proves the connection to that specific domain is encrypted, not that the domain is the real organization, so a lookalike URL signals fraud.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An expired certificate</b>: the scenario says the certificate is valid.</span><span class='qd'><b>A DDoS attack</b>: that disrupts availability, not domain impersonation.</span><span class='qd'><b>A boot sector virus</b>: a local malware issue, unrelated to a misspelled URL.</span>" },
{ id:"D2-108", domain:2, obj:"2.10", diff:"medium", q:"What role do digital certificates play when connecting to an HTTPS website?", options:["They verify the server's identity and enable an encrypted TLS session","They speed up the connection by caching pages","They store the user's passwords","They block pop-up windows"], answer:0, explain:"<strong>They verify the server's identity and enable an encrypted TLS session</strong> is correct because certificates bind a public key to a domain validated by a certificate authority, allowing trusted, encrypted communication.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They speed up the connection by caching pages</b>: certificates do not cache content.</span><span class='qd'><b>They store the user's passwords</b>: that is a password manager's function.</span><span class='qd'><b>They block pop-up windows</b>: handled by the pop-up blocker.</span>" },
{ id:"D2-109", domain:2, obj:"2.1", diff:"medium", q:"Which device authenticates a user by reading a chip embedded in a card the user inserts or taps?", options:["Smart card reader","Bollard","Surveillance camera","Cable lock"], answer:0, explain:"<strong>Smart card reader</strong> is correct because it reads the cryptographic chip in a smart card to authenticate a 'something you have' credential.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bollard</b>: blocks vehicles.</span><span class='qd'><b>Surveillance camera</b>: monitors activity but does not authenticate.</span><span class='qd'><b>Cable lock</b>: physically secures equipment.</span>" },
{ id:"D2-110", domain:2, obj:"2.2", diff:"easy", q:"Which Wi-Fi setup feature is considered insecure because its PIN method can be brute forced, and should generally be disabled?", options:["WPS","WPA3","AES","RADIUS"], answer:0, explain:"<strong>WPS</strong> is correct because Wi-Fi Protected Setup's PIN can be guessed in a feasible number of attempts, so it should be turned off.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>WPA3</b>: the current secure standard, not the insecure feature.</span><span class='qd'><b>AES</b>: a strong encryption cipher.</span><span class='qd'><b>RADIUS</b>: provides centralized authentication, not the vulnerable setup PIN.</span>" },
{ id:"D2-111", domain:2, obj:"2.3", diff:"medium", q:"Which tool is the primary defense for detecting and removing viruses, trojans, and other malicious software on a workstation?", options:["Anti-malware/antivirus software","A pop-up blocker","Disk Defragmenter","A password manager"], answer:0, explain:"<strong>Anti-malware/antivirus software</strong> is correct because it scans, detects, quarantines, and removes malicious software using signatures and behavior analysis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A pop-up blocker</b>: blocks browser pop-ups, not system malware.</span><span class='qd'><b>Disk Defragmenter</b>: optimizes file layout.</span><span class='qd'><b>A password manager</b>: stores credentials, not a malware scanner.</span>" },
{ id:"D2-112", domain:2, obj:"2.4", diff:"medium", q:"An attacker pretends to be a delivery driver and convinces a receptionist to hold a secured door open. Which broad category does this manipulation fall under?", options:["Social engineering","SQL injection","Zero-day exploit","Cross-site scripting"], answer:0, explain:"<strong>Social engineering</strong> is correct because the attacker manipulates a person's trust and helpfulness to gain unauthorized access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SQL injection</b>: a database input attack.</span><span class='qd'><b>Zero-day exploit</b>: targets an unknown software flaw.</span><span class='qd'><b>Cross-site scripting</b>: injects scripts into web pages.</span>" },
{ id:"D2-113", domain:2, obj:"2.5", diff:"easy", q:"Which Windows tool is used to create and manage local user accounts and group memberships on a standalone PC?", options:["Local Users and Groups (lusrmgr.msc)","Disk Management","Event Viewer","Resource Monitor"], answer:0, explain:"<strong>Local Users and Groups (lusrmgr.msc)</strong> is correct because it manages local accounts and assigns them to groups on a single computer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disk Management</b>: manages partitions and volumes.</span><span class='qd'><b>Event Viewer</b>: shows logs.</span><span class='qd'><b>Resource Monitor</b>: displays performance data.</span>" },
{ id:"D2-114", domain:2, obj:"2.6", diff:"medium", q:"Which practice helps prevent an attacker from repeatedly guessing a user's password by locking the account after several failed attempts?", options:["Account lockout policy","Enabling AutoPlay","Disabling the firewall","Shortening the password"], answer:0, explain:"<strong>Account lockout policy</strong> is correct because it temporarily disables an account after a set number of failed logins, thwarting brute-force guessing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Enabling AutoPlay</b>: increases media risk, unrelated to login attempts.</span><span class='qd'><b>Disabling the firewall</b>: reduces protection.</span><span class='qd'><b>Shortening the password</b>: makes guessing easier, not harder.</span>" },
{ id:"D2-115", domain:2, obj:"2.7", diff:"medium", q:"What does enabling a passcode or PIN screen lock on a mobile device primarily protect against?", options:["Unauthorized access if the device is lost or left unattended","Battery drain","Slow app loading","Weak cellular signal"], answer:0, explain:"<strong>Unauthorized access if the device is lost or left unattended</strong> is correct because a screen lock requires authentication before anyone can use the device.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Battery drain</b>: a screen lock does not manage battery life.</span><span class='qd'><b>Slow app loading</b>: unrelated to locking.</span><span class='qd'><b>Weak cellular signal</b>: not affected by a passcode.</span>" },
{ id:"D2-116", domain:2, obj:"2.8", diff:"medium", q:"A low-level format differs from a standard format in that it does what?", options:["Overwrites the drive at a sector level, more thoroughly erasing data","Only renames the volume label","Encrypts the boot sector","Compresses files to save space"], answer:0, explain:"<strong>Overwrites the drive at a sector level, more thoroughly erasing data</strong> is correct because a low-level format writes over sectors, making data far harder to recover than a standard format.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only renames the volume label</b>: that is a trivial change, not a low-level format.</span><span class='qd'><b>Encrypts the boot sector</b>: formatting does not encrypt.</span><span class='qd'><b>Compresses files to save space</b>: compression is unrelated to formatting for destruction.</span>" },
{ id:"D2-117", domain:2, obj:"2.9", diff:"medium", q:"Why is it risky to leave UPnP enabled on a SOHO router?", options:["It can let malware automatically open inbound ports without user approval","It disables Wi-Fi encryption","It blocks all internet access","It deletes the firmware"], answer:0, explain:"<strong>It can let malware automatically open inbound ports without user approval</strong> is correct because Universal Plug and Play allows applications to request port mappings, which malicious software can abuse to expose the network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It disables Wi-Fi encryption</b>: UPnP does not control encryption.</span><span class='qd'><b>It blocks all internet access</b>: it does not block connectivity.</span><span class='qd'><b>It deletes the firmware</b>: UPnP does not erase firmware.</span>" },
{ id:"D2-118", domain:2, obj:"2.10", diff:"medium", q:"Which action best protects a user from entering credentials on a fraudulent website?", options:["Verify the URL and that the connection uses HTTPS with a valid certificate before logging in","Trust any site that loads quickly","Enter credentials only on HTTP sites","Disable the pop-up blocker"], answer:0, explain:"<strong>Verify the URL and that the connection uses HTTPS with a valid certificate before logging in</strong> is correct because confirming the correct domain and a valid encrypted connection reduces the chance of submitting data to a phishing site.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust any site that loads quickly</b>: speed has nothing to do with legitimacy.</span><span class='qd'><b>Enter credentials only on HTTP sites</b>: HTTP is unencrypted and unsafe.</span><span class='qd'><b>Disable the pop-up blocker</b>: removing it increases exposure to malicious pop-ups.</span>" },
{ id:"D2-119", domain:2, obj:"2.1", diff:"hard", q:"A facility uses badge readers plus a PIN keypad and a security guard at the entrance. Layering multiple independent controls like this is best described as what?", options:["Defense in depth","Single sign-on","Implicit deny","Mandatory access control"], answer:0, explain:"<strong>Defense in depth</strong> is correct because it layers multiple controls so that if one fails, others still protect the asset.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Single sign-on</b>: a convenience authentication scheme, not layered physical controls.</span><span class='qd'><b>Implicit deny</b>: a default-deny rule on access lists.</span><span class='qd'><b>Mandatory access control</b>: an access model based on classifications, not layered entry controls.</span>" },
{ id:"D2-120", domain:2, obj:"2.3", diff:"hard", q:"A user reports their browser homepage keeps changing, new toolbars appear, and they see frequent ads. After confirming symptoms, which initial remediation steps follow CompTIA best practice?", options:["Quarantine the system, disable System Restore, then remediate with updated anti-malware","Reinstall the OS immediately without investigating","Delete the browser and reinstall Windows","Ignore it since ads are harmless"], answer:0, explain:"<strong>Quarantine the system, disable System Restore, then remediate with updated anti-malware</strong> is correct because the malware best-practice flow is to isolate the machine, disable System Restore, and clean with current tools and definitions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reinstall the OS immediately without investigating</b>: skips standard remediation that often resolves adware.</span><span class='qd'><b>Delete the browser and reinstall Windows</b>: excessive and skips proper steps.</span><span class='qd'><b>Ignore it since ads are harmless</b>: adware can carry further risk and degrades the system.</span>" },
{ id:"D2-121", domain:2, obj:"2.4", diff:"hard", q:"Users receive a text message claiming their bank account is locked, with a link to 'verify' their login. What specific social engineering attack is this?", options:["Smishing","Whaling","Tailgating","Dumpster diving"], answer:0, explain:"<strong>Smishing</strong> is correct because it is phishing carried out through SMS text messages to lure victims to fraudulent links or numbers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whaling</b>: targets high-level executives, typically via email.</span><span class='qd'><b>Tailgating</b>: a physical access attack.</span><span class='qd'><b>Dumpster diving</b>: searching trash for information.</span>" },
{ id:"D2-122", domain:2, obj:"2.5", diff:"hard", q:"A standard user needs to install an approved printer driver that requires elevation. Which Windows mechanism prompts for administrator credentials to allow this action?", options:["User Account Control (UAC)","BitLocker","EFS","Group Policy preferences"], answer:0, explain:"<strong>User Account Control (UAC)</strong> is correct because UAC intercepts the privileged action and prompts for admin credentials before allowing the change.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>BitLocker</b>: encrypts volumes, not an elevation prompt.</span><span class='qd'><b>EFS</b>: encrypts files.</span><span class='qd'><b>Group Policy preferences</b>: deploys settings but is not the per-action elevation prompt.</span>" },
{ id:"D2-123", domain:2, obj:"2.7", diff:"hard", q:"An organization wants to ensure that lost smartphones storing corporate data can be located and erased, and that only managed apps can access company resources. Which combination best meets these goals?", options:["MDM enrollment with remote locate/wipe and managed app policies","Disabling all encryption and screen locks","Allowing only personal email apps","Turning off location services permanently"], answer:0, explain:"<strong>MDM enrollment with remote locate/wipe and managed app policies</strong> is correct because MDM provides remote location and wipe plus controls over which apps can access corporate data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disabling all encryption and screen locks</b>: removes core protections.</span><span class='qd'><b>Allowing only personal email apps</b>: does not secure corporate data.</span><span class='qd'><b>Turning off location services permanently</b>: prevents locating a lost device.</span>" },
{ id:"D2-124", domain:2, obj:"2.9", diff:"easy", q:"Which SOHO setting changes the network name that wireless clients see when searching for available Wi-Fi networks?", options:["SSID","WPA2 key","Subnet mask","Default gateway"], answer:0, explain:"<strong>SSID</strong> is correct because the Service Set Identifier is the broadcast network name that identifies a wireless network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>WPA2 key</b>: the passphrase used to connect, not the displayed name.</span><span class='qd'><b>Subnet mask</b>: defines the network's address range.</span><span class='qd'><b>Default gateway</b>: the router address used to reach other networks.</span>" },
{ id:"D2-125", domain:2, obj:"2.10", diff:"medium", q:"A coworker emails a link claiming to be a shared document, but hovering over it shows a completely unrelated, suspicious URL. What is the safest browser-security action?", options:["Do not click the link and verify with the sender through another channel","Click it quickly before it expires","Forward it to all colleagues to warn them by sharing the link","Open it in private browsing to stay safe"], answer:0, explain:"<strong>Do not click the link and verify with the sender through another channel</strong> is correct because a mismatched URL is a classic phishing sign, and confirming out-of-band avoids falling for the lure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Click it quickly before it expires</b>: urgency is a manipulation tactic and clicking is risky.</span><span class='qd'><b>Forward it to all colleagues to warn them by sharing the link</b>: spreads the malicious link further.</span><span class='qd'><b>Open it in private browsing to stay safe</b>: private mode offers no protection against malicious sites.</span>" }
);
